
/* ============================================================
   MOBILIZAPRO — CORREÇÃO DO LOGIN
   Causa corrigida: a limpeza do aviso de acesso inicial estava removendo
   o card inteiro do login em alguns cenários.
   ============================================================ */
(function(){
    const MOBI_LOGIN_LOGO = "data:image/png;base64,";

    function mproEnsureDefaultAdmin() {
        try {
            let users = [];
            try { users = JSON.parse(localStorage.getItem(MOBI_ACCESS_USERS_KEY) || '[]'); } catch(e) { users = []; }
            if (!Array.isArray(users)) users = [];

            const cleanDefaultCpf = accessCpf(MOBI_DEFAULT_ADMIN.cpf);
            let idx = users.findIndex(u => accessCpf(u && u.cpf) === cleanDefaultCpf);

            if (idx < 0) {
                users.push(sanitizeAccessUser(MOBI_DEFAULT_ADMIN));
            } else {
                const existing = sanitizeAccessUser(users[idx]);
                existing.name = existing.name || MOBI_DEFAULT_ADMIN.name;
                existing.cpf = cleanDefaultCpf;
                existing.email = existing.email || MOBI_DEFAULT_ADMIN.email;
                existing.role = 'GERENCIAL';
                existing.active = true;
                existing.password = existing.password || MOBI_DEFAULT_ADMIN.password || '123456';
                users[idx] = existing;
            }

            if (!users.some(u => u && u.role === 'GERENCIAL' && u.active !== false)) {
                users.push(sanitizeAccessUser(MOBI_DEFAULT_ADMIN));
            }

            setAccessUsers(users);
            return users.map(sanitizeAccessUser);
        } catch(error) {
            console.error('Falha ao garantir administrador padrão', error);
            return [sanitizeAccessUser(MOBI_DEFAULT_ADMIN)];
        }
    }

    function mproIsLogged() {
        try { return Boolean(getCurrentAccessUser && getCurrentAccessUser()); } catch(e) { return false; }
    }

    function mproRenderCleanLogin() {
        const container = document.getElementById('page-acesso');
        if (!container) return;

        container.innerHTML = `
            <div class="max-w-xl mx-auto animate-up">
                <div class="mb-6 flex justify-center">
                    <div class="w-full max-w-[420px] rounded-3xl border border-primary/20 bg-[linear-gradient(135deg,rgba(10,21,54,0.95),rgba(5,15,42,0.98))] px-8 py-8 shadow-[0_20px_60px_rgba(0,0,0,0.35)]">
                        ${MOBI_LOGIN_LOGO ? `<img src="${MOBI_LOGIN_LOGO}" alt="MobilizaPRO" class="w-full h-auto object-contain">` : `<div class="text-4xl font-black text-primary text-center">MobilizaPRO</div>`}
                    </div>
                </div>

                <div class="card rounded-3xl p-7 border-l-4 border-l-primary">
                    <div class="flex items-center gap-3 mb-6">
                        <span class="material-symbols-outlined text-primary text-4xl">manage_accounts</span>
                        <div>
                            <h3 class="font-display font-black text-2xl">Acesso ao Sistema</h3>
                            <p class="text-xs text-muted">Entre com CPF e senha para acessar o MobilizaPRO.</p>
                        </div>
                    </div>
                    <div class="space-y-4">
                        <div>
                            <label class="text-[10px] font-bold uppercase text-muted block mb-1">CPF</label>
                            <input id="login-cpf" class="modal-input font-mono" inputmode="numeric" maxlength="14" placeholder="000.000.000-00" oninput="maskCpfInput(this)" autocomplete="username">
                        </div>
                        <div>
                            <label class="text-[10px] font-bold uppercase text-muted block mb-1">Senha</label>
                            <input id="login-password" type="password" class="modal-input" placeholder="SENHA DE ACESSO" onkeydown="if(event.key==='Enter') loginAccessUser()" autocomplete="current-password">
                        </div>
                        <button onclick="loginAccessUser()" class="btn btn-primary w-full">
                            <span class="material-symbols-outlined text-sm">login</span> Entrar
                        </button>
                    </div>
                </div>
            </div>
        `;

        setTimeout(() => {
            try {
                const first = document.getElementById('login-cpf');
                if (first) first.focus();
            } catch(e) {}
        }, 0);
    }

    // Override definitivo do login para funcionar com sessão runtime e usuários locais.
    window.loginAccessUser = loginAccessUser = function() {
        mproEnsureDefaultAdmin();

        const cpf = accessCpf(document.getElementById('login-cpf')?.value || '');
        const password = String(document.getElementById('login-password')?.value || '');
        const user = getAccessUsers().find(u => accessCpf(u.cpf) === cpf && String(u.password || '') === password && u.active !== false);

        if (!user) return alert('CPF ou senha inválidos.');

        try { window.MOBI_RUNTIME_ACCESS_CPF = cpf; } catch(e) {}
        try { sessionStorage.setItem(MOBI_ACCESS_SESSION_KEY, cpf); } catch(e) {}
        try { localStorage.removeItem(MOBI_ACCESS_SESSION_KEY); } catch(e) {}

        if (typeof updateAccessBadge === 'function') updateAccessBadge();
        if (typeof mproApplyLoginVisibility === 'function') mproApplyLoginVisibility();
        if (typeof selectPage === 'function') selectPage('dashboard');
        else if (typeof renderCurrentPage === 'function') renderCurrentPage();
    };

    const previousRenderAcessoLoginFix = typeof renderAcesso === 'function' ? renderAcesso : null;
    window.renderAcesso = renderAcesso = function() {
        mproEnsureDefaultAdmin();

        if (!mproIsLogged()) {
            mproRenderCleanLogin();
            if (typeof mproApplyLoginVisibility === 'function') setTimeout(mproApplyLoginVisibility, 0);
            return;
        }

        const result = previousRenderAcessoLoginFix ? previousRenderAcessoLoginFix.apply(this, arguments) : undefined;

        // Remoção precisa: somente o aviso antigo, nunca o card inteiro.
        setTimeout(() => {
            const page = document.getElementById('page-acesso');
            if (!page) return;
            Array.from(page.querySelectorAll('.rounded-xl, .text-muted, div')).forEach(el => {
                const txt = (el.textContent || '').replace(/\s+/g, ' ').trim();
                if (/Acesso inicial/i.test(txt)) el.remove();
            });
        }, 0);

        return result;
    };

    const previousRequireLogin = typeof window.requireLoginOnAppOpen === 'function' ? window.requireLoginOnAppOpen : null;
    window.requireLoginOnAppOpen = function() {
        try { window.MOBI_RUNTIME_ACCESS_CPF = ''; } catch(e) {}
        try { sessionStorage.removeItem(MOBI_ACCESS_SESSION_KEY); } catch(e) {}
        try { localStorage.removeItem(MOBI_ACCESS_SESSION_KEY); } catch(e) {}

        if (typeof selectPage === 'function') selectPage('acesso');
        else renderAcesso();

        if (typeof updateAccessBadge === 'function') updateAccessBadge();
        if (typeof mproApplyLoginVisibility === 'function') mproApplyLoginVisibility();
    };

    // Inicialização segura.
    if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', () => {
            mproEnsureDefaultAdmin();
            setTimeout(() => {
                if (!mproIsLogged()) renderAcesso();
            }, 80);
        });
    } else {
        mproEnsureDefaultAdmin();
        setTimeout(() => {
            if (!mproIsLogged()) renderAcesso();
        }, 80);
    }
})();
